Each query includes a:

- [$limit](manual/reference/operator/aggregation/limit) stage to limit the output to 4 results.

- [$project](manual/reference/operator/aggregation/project) stage to exclude all fields except `title`.

```js
const { MongoClient } = require("mongodb");

// connect to your Atlas cluster
const uri =
    "<connection-string>";

const client = new MongoClient(uri);

async function run() {
    try {
        await client.connect();

        // set namespace
        const database = client.db("sample_mflix");
        const coll = database.collection("movies");

        // define pipeline
        const agg = [
            {$search: {autocomplete: {query: "men with", path: "title", tokenOrder: "any"}}},
            {$limit: 4},
            {$project: {_id: 0,title: 1}}
        ];
        // run pipeline
        const result = await coll.aggregate(agg);

        // print results
        await result.forEach((doc) => console.log(doc));
    } finally {
        await client.close();
    }
}
run().catch(console.dir);

